# BEST PRACTICE: Adaptive tokenization with fallback strategy
from tokenizers import Tokenizer, models, pre_tokenizers, processors

# Good: Select tokenizer based on task requirements
class CricketTokenizationPipeline:
    def __init__(self, task_type, vocab_size=32000):
        self.task_type = task_type

        if task_type == "machine_translation":
            # BPE for morphological consistency across language pairs
            self.tokenizer = Tokenizer(models.BPE(vocab_size=vocab_size))
            self.tokenizer.pre_tokenizer = pre_tokenizers.Whitespace()
            self.merge_strategy = "frequency"  # Merge high-frequency pairs first

        elif task_type == "classification":
            # WordPiece for supervised NLP tasks
            self.tokenizer = Tokenizer(models.WordPiece(vocab_size=vocab_size))
            self.tokenizer.pre_tokenizer = pre_tokenizers.BertPreTokenizer()
            self.merge_strategy = "greedy"  # Maximize vocabulary hits

        elif task_type == "multilingual":
            # SentencePiece for language-agnostic systems
            self.tokenizer = Tokenizer(models.SentencePiece())
            self.merge_strategy = "unigram"  # Probabilistic selection

    def tokenize_match(self, text, batsman_stats):
        """Tokenize cricket commentary with task-aware strategy"""
        tokens = self.tokenizer.encode(text).tokens
        return {"tokens": tokens, "strategy": self.merge_strategy}

# ANTI-PATTERN: One-size-fits-all tokenization
class PoorCricketTokenization:
    def __init__(self):
        # Bad: Using BPE vocabulary (8K) for multilingual character-heavy language
        self.tokenizer = Tokenizer(models.BPE(vocab_size=8000))
        # Problem: Character languages like Hindi need 50K+ subword units
        # Result: ~35% of tokens become [UNK], losing semantic information

    def tokenize_match(self, hindi_commentary):
        tokens = self.tokenizer.encode(hindi_commentary).tokens
        # Returns excessive [UNK] tokens, degrading downstream task performance
        return tokens

# BEST PRACTICE: Vocabulary size calibration
def calibrate_vocab_for_task(task_type, corpus_size_gb, inference_latency_ms):
    """Determine optimal vocabulary size like selecting bowling rotation depth"""
    vocab_configs = {
        "low_latency": {"vocab_size": 8000, "max_sequence": 128},      # Fast bowlers only
        "balanced": {"vocab_size": 32000, "max_sequence": 256},        # Mixed attack
        "high_accuracy": {"vocab_size": 50000, "max_sequence": 512},   # Full squad rotation
    }

    if inference_latency_ms < 50:
        return vocab_configs["low_latency"]
    elif corpus_size_gb > 100:
        return vocab_configs["high_accuracy"]
    else:
        return vocab_configs["balanced"]
